import { Box, Button, Stack, Typography } from '@mui/material';
import { useRouter } from 'next/router';
import { ReactElement, useEffect, useState } from 'react';

import DocumentsLayout from '@/layouts/documents.layout';

const privacyPolicyContent = {
  ja: {
    title: 'プライバシーポリシー',
    sections: [
      {
        title: '',
        content: '株式会社Knowhere（以下「当社」といいます）は、当社が提供するサービス「SmartScout」（以下「本サービス」といいます）においてユーザーの個人情報を適切に取り扱うために、本プライバシーポリシー（以下「本ポリシー」といいます）を定めます。なお、当社は個人情報の保護に関する法律その他の関連法令を遵守し、ユーザーの個人情報を適切に管理・保護いたします。\n\n本ポリシーにおいて「個人情報保護法」とは、個人情報の保護に関する法律を意味し、「個人情報」とは、個人情報保護法第2条第1項により定義される個人情報を意味し、「本人」とは、個人情報の主体である個人を意味するものとします。'
      },
      {
        title: '第1条 事業者情報',
        content: '事業者の名称： 株式会社Knowhere'
      },
      {
        title: '第2条 収集する情報',
        content: '当社は、本サービスの提供にあたり、ユーザーから以下の情報を収集します。\n\n・ユーザーから提供される情報: 氏名、住所、電話番号、メールアドレス等の連絡先情報、生年月日などのプロフィール情報、および本サービスの利用登録やお問い合わせ時にユーザーが入力または送信する情報。\n・本サービスの利用に際して提供される、ユーザーのプレイ映像（投球動作、打撃動作を含むが、これらに限られない）に関するデータ。\n・プレイデータ等の利用履歴情報: ユーザーが本サービスを利用する過程で収集される、ゲームのプレイデータや利用履歴に関する情報（例：プレイの記録やスコア、利用時間、操作履歴など）。\n・位置情報: ユーザーが本サービスで位置情報の利用を許可した場合に取得される、端末の位置情報データ。\n・デバイス情報等: 本サービス利用時に自動的に収集されるユーザーの端末に関する情報（例：デバイスの種類・OS・端末識別子、IPアドレス、ブラウザ情報等のログ情報）。\n・決済に関する情報: 本サービスで有料コンテンツの購入や課金を行う際に取得される、クレジットカード情報やその他の決済手段に関する情報。これには、決済処理のために必要となるApple社やStripe社等の外部サービスを利用する場合に取得される情報が含まれます。'
      },
      {
        title: '第3条 個人情報の利用目的',
        content: '当社は、取得したユーザーの個人情報を以下の目的のために利用いたします。また、当社は個人情報を非識別化または統計化することがあります。\n\n・本サービスの機能を提供・運営するため（スカウトとの連携機能の提供等、本サービスの円滑な利用を実現する目的を含みます）。\n・ユーザーからのお問い合わせやご相談に対応し、適切なサポートを行うため。\n・当社のサービスに関する最新情報、更新内容、キャンペーン情報等をユーザーに通知（メール送信等）し、マーケティングに活用するため。\n・ユーザーによる本サービスの利用状況を分析し、サービスの利用状況把握や新機能の開発、既存サービスの改善に役立てるため。\n・ユーザーに適した広告やプロモーションコンテンツを、本サービス上または提携する第三者の媒体上で表示・配信するため。\n・本サービスの安全な利用環境を確保するため、不正アクセスや不正利用の監視・防止、利用規約に違反する行為への対応等を行うため。\n・ユーザーが有料サービスを利用した場合に利用料金の請求や決済処理を行うため。\n・上記の利用目的に付随し、またはこれらに関連する事項を遂行するため。\n\n当社は、個人情報保護法その他の法令により許容される場合を除き、本人の同意を得ず、利用目的の達成に必要な範囲を超えて個人情報を取り扱いません。ただし、次の場合はこの限りではありません。\n\n・法令に基づく場合。\n・人の生命、身体または財産の保護のために必要がある場合であって、本人の同意を得ることが困難であるとき。\n・公衆衛生の向上または児童の健全な育成の推進のため特に必要がある場合であって、本人の同意を得ることが困難であるとき。\n・国の機関もしくは地方公共団体、またはその委託を受けた者が法令の定める事務を遂行するうえで協力する必要がある場合であって、本人の同意取得によって当該事務の遂行に支障を及ぼすおそれがあるとき。\n・学術研究機関等に個人データを提供する場合であって、当該学術研究機関等が当該個人データを学術研究目的で取り扱う必要があるとき（当該個人データを取り扱う目的の一部が学術研究目的である場合を含み、個人の権利利益を不当に侵害するおそれがある場合を除く。）。'
      },
      {
        title: '第4条 個人情報の第三者提供',
        content: '当社は、ユーザーの個人情報について、前条に規定する場合のいずれかに該当する場合を除き、ユーザー本人の同意なく第三者に提供することはいたしません。ただし、次に掲げる必要があり第三者に提供する場合はこの限りではありません。\n\n・当社が利用目的の達成に必要な範囲内において個人情報の取扱いの全部または一部を委託する場合\n・合併その他の事由による事業の承継に伴って個人情報が提供される場合\n・その他、個人情報保護法その他の法令で認められる場合\n\n※なお、ユーザーの個人情報を国外の第三者に提供する場合には、個人情報保護法その他の法令に従い必要な措置（ユーザーの同意取得等）を講じた上で行います。'
      },
      {
        title: '第5条 個人情報の取扱いの委託',
